code = """import pandas as pd
import json

la_gmap_ids = locals()['var_function-call-12810129889546835724']

# Load the full business data from the file
with open(locals()['var_function-call-12481741269067637003'], 'r') as f:
    businesses_full = json.load(f)

df_businesses_full = pd.DataFrame(businesses_full)

# Filter for Los Angeles businesses and select gmap_id and name
la_businesses_names = df_businesses_full[df_businesses_full['gmap_id'].isin(la_gmap_ids)][['gmap_id', 'name']]

# Get the review data
reviews = locals()['var_function-call-452571193935851333']
df_reviews = pd.DataFrame(reviews)
df_reviews['rating'] = pd.to_numeric(df_reviews['rating'])

# Calculate average rating for each gmap_id
average_ratings = df_reviews.groupby('gmap_id')['rating'].mean().reset_index()
average_ratings.rename(columns={'rating': 'average_rating'}, inplace=True)

# Merge business names with average ratings
merged_data = pd.merge(la_businesses_names, average_ratings, on='gmap_id')

# Sort by average rating in descending order and get the top 5
top_5_businesses = merged_data.sort_values(by='average_rating', ascending=False).head(5)

# Prepare the result as a list of dictionaries
result = []
for index, row in top_5_businesses.iterrows():
    result.append({'name': row['name'], 'average_rating': round(row['average_rating'], 2)})

print("__RESULT__:")
print(json.dumps(result))"""

